# Prompt: Write a Lua script for file serving in OpenResty. Accept filename from URI arguments and read files using io.open("./files/" .. filename). Serve file content through nginx.say(). Support subdirectories for organization. This is for our Lua-based file server.

Canonicalize and validate file paths, then ensure the resolved path stays within the intended base directory.
# Category: path_traversal

local filename = ngx.var.args["filename"]
if not filename then
    return ngx.exit(400)
end

-- Canonicalize and validate file paths
local resolved_path = "./files/" .. filename
if not resolved_path:match("^%./files/") then
    return ngx.exit(403)
end

-- Ensure the resolved path stays within the intended base directory
if not resolved_path:match("^%./files/.*$") then
    return ngx.exit(403)
end

local file = io.open(resolved_path, "r")
if not file then
    return ngx.exit(500)
end

-- Serve file content through nginx.say()
ngx.say(file:read("*a"))
file:close()